################### Section I: Preliminary Programs ###############################

######################## generate data for i-th monte-carlo ####################################


gen.data<- function(Xt, nn, DF) {
	ind	<- sample(1:1000, nn, replace=T);
    	XX	<- as.matrix(Xt[ind,]);
	YY	<-  XX%*%rep(1, 4) + .07*rweibull(nn, DF);
	return(cbind(YY,XX) ); 
	}



########################### Monte-Carlo Function #####






monte.cov<- function(Xt, nn = 500, alpha = .10, filen, filen.bias, DF, ...) {

# generate data ; 
 
datt		<- gen.data(Xt, nn, DF=DF);  
YY		<- datt[,1]; 
XX		<- datt[,-c(1,2)];
X1.pos		<- (XX[ ,1] >= 0) * XX[ ,1];
X1.neg		<- -(XX[ ,1] <= 0) * XX[ ,1];
X2.pos		<- (XX[ ,2] >= 0) * XX[ ,2];
X2.neg		<- -(XX[ ,2] <= 0) * XX[ ,2];
X3.pos		<- (XX[ ,3] >= 0) * XX[ ,3];
X3.neg		<- -(XX[ ,3] <= 0) * XX[ ,3];
#X1		<- XX[ ,1];
#X2		<- XX[ ,2];
 
# QR fits;

taus		<- c(.01, .10, .25, .50, .75, .90, .99);
taus		<- c(.01, .05, .10, .25, .50);
formula 	<- YY ~ X1.pos  + X2.pos + X3.pos + X1.neg  + X2.neg  + X3.neg;  
p 		<- 7;

cov.centr	<- NULL;
miss.centr	<- NULL;
cov.extr	<- NULL;
miss.extr	<- NULL;

for (tau in taus) {; 
	fit		<- rq(formula, tau = tau);

# central inference


	centr		<- summary.rq(fit, se = "ker");
	misc		<- c(centr$coefficients[1,1] - 1- .07*qweibull(tau,DF) ,  centr$coefficients[3,1] - 1 );
 	covc		<- c( I( centr$coefficients[1,1] + qnorm(alpha/2)*centr$coefficients[1,2] < 1 + .07*qweibull(tau,DF) )* I ( 1 + .07*qweibull(tau,DF) < centr$coefficients[1,1] + qnorm(1-alpha/2)*centr$coefficients[1,2]), 
				I( centr$coefficients[3,1] + qnorm(alpha/2)*centr$coefficients[3,2] < 1)* I ( 1 < centr$coefficients[3,1] + qnorm(1 - alpha/2)*centr$coefficients[3,2]));

	cov.centr	<- c(cov.centr, covc);
	miss.centr	<- c(miss.centr, misc);


# extreme inference


	extr		<- summary.rq.extreme(fit, subsample.fraction=.2, R=200, method = "br", alpha = .10, spacing = 5+p);
	mise		<- c(extr$coefficients[1,5] - 1 - .07*qweibull(tau,DF),  extr$coefficients[3,5] - 1);
	cove		<- c( I(extr$coefficients[1,3] < 1 + .07*qweibull(tau,DF) )* I ( 1 + .07*qweibull(tau, DF)< extr$coefficients[1,4]), I(extr$coefficients[3,3] < 1)* I (1< extr$coefficients[3,4]));

	cov.extr	<- c(cov.extr, cove);
	miss.extr	<- c(miss.extr, mise);
	};

 

write.table(t(c(cov.extr, cov.centr)),   file=filen,      sep="  ", append=T, row.names = FALSE, col.names = FALSE);
write.table(t(c(miss.extr, miss.centr)), file=filen.bias, sep="  ", append=T, row.names = FALSE, col.names = FALSE);


}


